```class Solution {
    public int maximumXOR(int[] nums) {
        TrieNode root = new TrieNode();
        int res = 0;
        for (int num : nums) {
            TrieNode cur = root;
            int temp = num;
            for (int i = 31; i >= 0; i--) {
                int bit = (temp >> i) & 1;
                if (cur.children[1 - bit] == null) {
                    cur.children[1 - bit] = new TrieNode();
                }
                cur = cur.children[1 - bit];
            }
            temp = 0;
            cur = root;
            for (int i = 31; i >= 0; i--) {
                int bit = (temp >> i) & 1;
                if (cur.children[bit] != null) {
                    temp |= 1 << i;
                    cur = cur.children[bit];
                } else {
                    cur = cur.children[1 - bit];
                }
            }
            res = Math.max(res, num ^ temp);
        }
        return res;
    }
}
